+/// Parse a partial auto-ID like "1000-*" → Some(1000).
+/// Returns None if the format doesn't match "ms-*".
+fn parse_partial_auto_id(arg: &[u8]) -> Option<u64> {
+    let text = std::str::from_utf8(arg).ok()?;
+    let (ms_str, seq_str) = text.split_once('-')?;
+    if seq_str != "*" {
+        return None;
+    }
+    ms_str.parse::<u64>().ok()
+}
